E = dir(30 + 4*360/5);
O = (0,0);

draw((-1.2,0)--(1.2,0));
draw((0,-1.2)--(0,1.2));
draw(Circle(O,1));
draw(O--A);
draw(O--B);
draw(O--C);
draw(O--D);
draw(O--E);

